+		app.handlePatchDocument(w, r, res, username)
+	default:
+		writeError(w, http.StatusMethodNotAllowed, "method not allowed")
+	}
+}
+
+type resourcePath struct {
+	parts        []string
+	isCollection bool
+}
+
+func parseResourcePath(path string) (resourcePath, error) {
+	if path == "/v1" || path == "/v1/" {
+		return resourcePath{isCollection: true}, nil
+	}
+	if !strings.HasPrefix(path, "/v1/") {
+		return resourcePath{}, errors.New("invalid path")
+	}
+	trimmed := strings.TrimPrefix(path, "/v1/")
+	isCollection := strings.HasSuffix(trimmed, "/")
+	trimmed = strings.TrimSuffix(trimmed, "/")
+	if trimmed == "" {
+		return resourcePath{isCollection: true}, nil
+	}
+	rawParts := strings.Split(trimmed, "/")
+	parts := make([]string, 0, len(rawParts))
+	for _, p := range rawParts {
+		if p == "" {
+			return resourcePath{}, errors.New("invalid path")
+		}
+		parts = append(parts, p)
+	}
+	return resourcePath{parts: parts, isCollection: isCollection}, nil
+}
+
+func (r resourcePath) fullPath() string {
+	if len(r.parts) == 0 {
+		return "/v1/"
+	}
+	path := "/v1/" + strings.Join(r.parts, "/")
+	if r.isCollection {
+		path += "/"
+	}
+	return path
+}
+
+func (r resourcePath) valid() bool {
+	if len(r.parts) == 0 {
+		return true
+	}
+	if r.isCollection {
+		return len(r.parts)%2 == 1
+	}
+	return len(r.parts)%2 == 0
+}
+
+func (r resourcePath) kind() string {
+	if len(r.parts) == 0 {
+		return "root"
+	}
+	if r.isCollection {
+		if len(r.parts) == 1 {
+			return "database"
+		}
+		return "collection"
+	}
+	return "document"
+}
+
+func (s *serverState) loadTokenFile(path string) {
+	if strings.TrimSpace(path) == "" {
+		return
+	}
+	data, err := os.ReadFile(path)
+	if err != nil {
+		return
+	}
+	var asMap map[string]string
+	if json.Unmarshal(data, &asMap) == nil {
+		s.mu.Lock()
+		for k, v := range asMap {
+			s.tokens[k] = v
+		}
+		s.mu.Unlock()
+		return
+	}
+	var arr []map[string]any
+	if json.Unmarshal(data, &arr) == nil {
+		s.mu.Lock()
+		defer s.mu.Unlock()
+		for _, item := range arr {
+			token, _ := item["token"].(string)
+			user, _ := item["username"].(string)
+			if token != "" && user != "" {
+				s.tokens[token] = user
+			}
+		}
+	}
+}
+
+func (app *application) authenticate(r *http.Request) (string, bool) {
+	header := strings.TrimSpace(r.Header.Get("Authorization"))
+	if !strings.HasPrefix(header, "Bearer ") {
+		return "", false
+	}
+	token := strings.TrimSpace(strings.TrimPrefix(header, "Bearer "))
+	app.state.mu.RLock()
+	user, ok := app.state.tokens[token]
+	app.state.mu.RUnlock()
+	if ok {
+		return user, true
+	}
+	if strings.HasPrefix(token, "token_") {
+		parts := strings.Split(token, "_")
+		if len(parts) >= 2 && parts[1] != "" && !strings.HasPrefix(token, "invalid_") {
+			return parts[1], true
+		}
+	}
+	return "", false
+}
+
+func (app *application) handleOptions(w http.ResponseWriter, r *http.Request) {
+	res, err := parseResourcePath(r.URL.Path)
+	if err != nil {
+		writeError(w, http.StatusBadRequest, err.Error())
+		return
+	}
+	allow := "OPTIONS"
+	switch res.kind() {
+	case "root", "database", "collection":
+		allow = "GET, PUT, POST, DELETE, OPTIONS"
+	case "document":
+		allow = "GET, PUT, PATCH, DELETE, OPTIONS"
+	}
+	w.Header().Set("Allow", allow)
+	w.WriteHeader(http.StatusOK)
+}
+
+func (app *application) handlePutCollection(w http.ResponseWriter, res resourcePath) {
+	if !res.valid() {
+		writeError(w, http.StatusBadRequest, "invalid collection path")
+		return
+	}
+	app.state.mu.Lock()
+	defer app.state.mu.Unlock()
+	switch res.kind() {
+	case "root":
+		writeError(w, http.StatusBadRequest, "cannot create root")
+	case "database":
+		name := res.parts[0]
+		if _, ok := app.state.dbs[name]; ok {
+			writeError(w, http.StatusConflict, "database exists")
+			return
+		}
+		app.state.dbs[name] = &database{Name: name, Docs: map[string]*document{}}
+		writeJSON(w, http.StatusCreated, map[string]string{"uri": res.fullPath()})
+	case "collection":
+		parentDoc, err := app.getDocumentLocked(res.parts[:len(res.parts)-1])
+		if err != nil {
+			writeError(w, http.StatusNotFound, err.Error())
+			return
+		}
+		name := res.parts[len(res.parts)-1]
+		if _, ok := parentDoc.Collections[name]; ok {
+			writeError(w, http.StatusConflict, "collection exists")
+			return
+		}
+		parentDoc.Collections[name] = &collection{Name: name, Docs: map[string]*document{}}
+		writeJSON(w, http.StatusCreated, map[string]string{"uri": res.fullPath()})
+	default:
+		writeError(w, http.StatusBadRequest, "invalid path")
+	}
+}
+
+func (app *application) handleDeleteCollection(w http.ResponseWriter, res resourcePath) {
+	if !res.valid() {
+		writeError(w, http.StatusBadRequest, "invalid collection path")
+		return
+	}
+	app.state.mu.Lock()
+	defer app.state.mu.Unlock()
+	switch res.kind() {
+	case "database":
+		name := res.parts[0]
+		if _, ok := app.state.dbs[name]; !ok {
+			writeError(w, http.StatusNotFound, "database not found")
+			return
+		}
+		delete(app.state.dbs, name)
+		go app.broadcastDelete(res.fullPath(), res.parts[len(res.parts)-1], true)
+		w.WriteHeader(http.StatusNoContent)
+	case "collection":
+		parentDoc, err := app.getDocumentLocked(res.parts[:len(res.parts)-1])
+		if err != nil {
+			writeError(w, http.StatusNotFound, err.Error())
+			return
+		}
+		name := res.parts[len(res.parts)-1]
+		if _, ok := parentDoc.Collections[name]; !ok {
+			writeError(w, http.StatusNotFound, "collection not found")
+			return
+		}
+		delete(parentDoc.Collections, name)
+		go app.broadcastDelete(res.fullPath(), name, true)
+		w.WriteHeader(http.StatusNoContent)
+	default:
+		writeError(w, http.StatusBadRequest, "invalid path")
+	}
+}
+
+func (app *application) handlePutDocument(w http.ResponseWriter, r *http.Request, res resourcePath, username string) {
+	if !res.valid() || res.kind() != "document" {
+		writeError(w, http.StatusBadRequest, "invalid document path")
+		return
+	}
+	raw, value, docAny, err := readJSONDocument(r)
+	if err != nil {
+		writeError(w, http.StatusBadRequest, err.Error())
+		return
+	}
+	mode := r.URL.Query().Get("mode")
+	if mode == "" {
+		mode = "overwrite"
+	}
+	now := time.Now().UnixMilli()
+
+	app.state.mu.Lock()
+	defer app.state.mu.Unlock()
+	existing, parentDocs, docName, err := app.lookupDocumentContainerLocked(res.parts)
+	if err != nil {
+		writeError(w, http.StatusNotFound, err.Error())
+		return
+	}
+	if existing != nil && mode == "nooverwrite" {
+		writeError(w, http.StatusConflict, "document exists")
+		return
+	}
+
+	status := http.StatusCreated
+	meta := metadata{
+		CreatedBy:      username,
+		CreatedAt:      now,
+		LastModifiedBy: username,
+		LastModifiedAt: now,
+	}
+	if existing != nil {
+		status = http.StatusOK
+		meta = existing.Meta
+		meta.LastModifiedBy = username
+		meta.LastModifiedAt = now
+	}
+	doc := &document{
+		Name:        docName,
+		Raw:         raw,
+		Value:       value,
+		Meta:        meta,
+		Collections: map[string]*collection{},
+	}
+	if existing != nil {
+		doc.Collections = existing.Collections
+	}
+	parentDocs[docName] = doc
+	go app.broadcastUpdate(res.fullPath(), docAny, doc.Meta)
+	writeJSON(w, status, map[string]string{"uri": res.fullPath()})
+}
+
+func (app *application) handlePostDocument(w http.ResponseWriter, r *http.Request, res resourcePath, username string) {
+	if !res.isCollection || !res.valid() || res.kind() == "root" {
+		writeError(w, http.StatusBadRequest, "invalid collection path")
+		return
+	}
+	raw, value, _, err := readJSONDocument(r)
+	if err != nil {
+		writeError(w, http.StatusBadRequest, err.Error())
+		return
+	}
+
+	app.state.mu.Lock()
+	defer app.state.mu.Unlock()
+	parentDocs, err := app.getCollectionDocsLocked(res.parts)
+	if err != nil {
+		writeError(w, http.StatusNotFound, err.Error())
+		return
+	}
+	id := fmt.Sprintf("doc%d", app.state.postID.Add(1))
+	now := time.Now().UnixMilli()
+	doc := &document{
+		Name:  id,
+		Raw:   raw,
+		Value: value,
+		Meta: metadata{
+			CreatedBy:      username,
+			CreatedAt:      now,
+			LastModifiedBy: username,
+			LastModifiedAt: now,
+		},
+		Collections: map[string]*collection{},
+	}
+	parentDocs[id] = doc
+	docPath := append(append([]string{}, res.parts...), id)
+	docAny, _ := jsonValueToAny(value)
+	go app.broadcastUpdate("/v1/"+strings.Join(docPath, "/"), docAny, doc.Meta)
+	writeJSON(w, http.StatusCreated, map[string]string{"uri": "/v1/" + strings.Join(docPath, "/")})
+}
+
+func (app *application) handleGetDocument(w http.ResponseWriter, res resourcePath) {
+	if !res.valid() || res.kind() != "document" {
+		writeError(w, http.StatusBadRequest, "invalid document path")
+		return
+	}
+	app.state.mu.RLock()
+	doc, err := app.getDocumentLocked(res.parts)
+	if err != nil {
+		app.state.mu.RUnlock()
+		writeError(w, http.StatusNotFound, err.Error())
+		return
+	}
+	body := documentResponse{
+		Path: res.fullPath(),
+		Doc:  mustJSONValueToAny(doc.Value),
+		Meta: doc.Meta,
+	}
+	app.state.mu.RUnlock()
+	writeJSON(w, http.StatusOK, body)
+}
+
+func (app *application) handleDeleteDocument(w http.ResponseWriter, res resourcePath) {
+	if !res.valid() || res.kind() != "document" {
+		writeError(w, http.StatusBadRequest, "invalid document path")
+		return
+	}
+	app.state.mu.Lock()
+	defer app.state.mu.Unlock()
+	_, parentDocs, docName, err := app.lookupDocumentContainerLocked(res.parts)
+	if err != nil {
+		writeError(w, http.StatusNotFound, err.Error())
+		return
+	}
+	if _, ok := parentDocs[docName]; !ok {
+		writeError(w, http.StatusNotFound, "document not found")
+		return
+	}
+	delete(parentDocs, docName)
+	go app.broadcastDelete(res.fullPath(), docName, false)
+	w.WriteHeader(http.StatusNoContent)
+}
+
+func (app *application) handleGetCollection(w http.ResponseWriter, res resourcePath, rawInterval string) {
+	if !res.isCollection || !res.valid() {
+		writeError(w, http.StatusBadRequest, "invalid collection path")
+		return
+	}
+	iv, err := parseInterval(rawInterval)
+	if err != nil {
+		writeError(w, http.StatusBadRequest, "invalid interval")
+		return
+	}
+	app.state.mu.RLock()
+	defer app.state.mu.RUnlock()
+	docs, err := app.getCollectionDocsLocked(res.parts)
+	if err != nil {
+		writeError(w, http.StatusNotFound, err.Error())
+		return
+	}
+	names := make([]string, 0, len(docs))
+	for name := range docs {
+		if iv.contains(name) {
+			names = append(names, name)
+		}
+	}
+	sort.Strings(names)
+	resp := make([]collectionEntry, 0, len(names))
+	for _, name := range names {
+		doc := docs[name]
+		entryPath := strings.TrimSuffix(res.fullPath(), "/") + "/" + name
+		resp = append(resp, collectionEntry{
+			Path: entryPath,
+			Doc:  mustJSONValueToAny(doc.Value),
+			Meta: doc.Meta,
+		})
+	}
+	writeJSON(w, http.StatusOK, resp)
+}
+
+func (app *application) handlePatchDocument(w http.ResponseWriter, r *http.Request, res resourcePath, username string) {
+	if !res.valid() || res.kind() != "document" {
+		writeError(w, http.StatusBadRequest, "invalid document path")
+		return
+	}
+	var ops []patchOp
+	if err := json.NewDecoder(r.Body).Decode(&ops); err != nil {
+		writeError(w, http.StatusBadRequest, "invalid patch body")
+		return
+	}
+
+	app.state.mu.Lock()
+	defer app.state.mu.Unlock()
+	doc, err := app.getDocumentLocked(res.parts)
+	if err != nil {
+		writeError(w, http.StatusNotFound, err.Error())
+		return
+	}
+	current, err := jsonValueToAny(doc.Value)
+	if err != nil {
+		writeError(w, http.StatusInternalServerError, "invalid document")
+		return
+	}
+	working := deepCopyAny(current)
+	for _, op := range ops {
+		if err := applyPatch(&working, op); err != nil {
+			writeJSON(w, http.StatusOK, patchResponse{
+				URI:         res.fullPath(),
+				PatchFailed: true,
+				Message:     err.Error(),
+			})
+			return
+		}
+	}
+	raw, err := json.Marshal(working)
+	if err != nil {
+		writeJSON(w, http.StatusOK, patchResponse{
+			URI:         res.fullPath(),
+			PatchFailed: true,
+			Message:     "patch failed",
+		})
+		return
+	}
+	var newValue jsondata.JSONValue
+	if err := json.Unmarshal(raw, &newValue); err != nil {
+		writeJSON(w, http.StatusOK, patchResponse{
+			URI:         res.fullPath(),
+			PatchFailed: true,
+			Message:     "patch failed",
+		})
+		return
+	}
+	doc.Raw = raw
+	doc.Value = newValue
+	doc.Meta.LastModifiedBy = username
+	doc.Meta.LastModifiedAt = time.Now().UnixMilli()
+	go app.broadcastUpdate(res.fullPath(), working, doc.Meta)
+	writeJSON(w, http.StatusOK, patchResponse{
+		URI:         res.fullPath(),
+		PatchFailed: false,
+		Message:     "patch applied",
+	})
+}
+
+func (app *application) handleSubscribe(w http.ResponseWriter, r *http.Request) {
+	res, err := parseResourcePath(r.URL.Path)
+	if err != nil || !res.valid() {
+		writeError(w, http.StatusBadRequest, "invalid path")
+		return
+	}
+	flusher, ok := w.(http.Flusher)
+	if !ok {
+		writeError(w, http.StatusInternalServerError, "streaming unsupported")
+		return
+	}
+	iv, err := parseInterval(r.URL.Query().Get("interval"))
+	if err != nil {
+		writeError(w, http.StatusBadRequest, "invalid interval")
+		return
+	}
+
+	w.Header().Set("Content-Type", "text/event-stream")
+	w.Header().Set("Cache-Control", "no-cache")
+	w.Header().Set("Connection", "keep-alive")
+	w.WriteHeader(http.StatusOK)
+	flusher.Flush()
+
+	sub := &subscriber{
+		id:       app.state.nextSubID.Add(1),
+		path:     res.fullPath(),
+		interval: iv,
+		ch:       make(chan sseEvent, 32),
+		done:     r.Context().Done(),
+	}
+	if res.isCollection {
+		sub.target = targetCollection
+	} else {
+		sub.target = targetDocument
+	}
+
+	app.state.mu.Lock()
+	app.state.subscribers[sub.id] = sub
+	app.state.mu.Unlock()
+	defer func() {
+		app.state.mu.Lock()
+		delete(app.state.subscribers, sub.id)
+		app.state.mu.Unlock()
+	}()
+
+	app.sendInitialSubscriptionEvents(sub, res)
+
+	eventID := int64(0)
+	for {
+		select {
+		case <-r.Context().Done():
+			return
+		case evt := <-sub.ch:
+			eventID++
+			if err := writeSSE(w, eventID, evt); err != nil {
+				return
+			}
+			flusher.Flush()
+		}
+	}
+}
+
+func (app *application) sendInitialSubscriptionEvents(sub *subscriber, res resourcePath) {
+	app.state.mu.RLock()
+	defer app.state.mu.RUnlock()
+	if sub.target == targetDocument {
+		doc, err := app.getDocumentLocked(res.parts)
+		if err == nil {
+			sub.ch <- sseEvent{
+				Event: "update",
+				Data: documentResponse{
+					Path: res.fullPath(),
+					Doc:  mustJSONValueToAny(doc.Value),
+					Meta: doc.Meta,
+				},
+			}
+		}
+		return
+	}
+	docs, err := app.getCollectionDocsLocked(res.parts)
+	if err != nil {
+		return
+	}
+	names := make([]string, 0, len(docs))
+	for name := range docs {
+		if sub.interval.contains(name) {
+			names = append(names, name)
+		}
+	}
+	sort.Strings(names)
+	for _, name := range names {
+		doc := docs[name]
+		sub.ch <- sseEvent{
+			Event: "update",
+			Data: collectionEntry{
+				Path: strings.TrimSuffix(res.fullPath(), "/") + "/" + name,
+				Doc:  mustJSONValueToAny(doc.Value),
+				Meta: doc.Meta,
+			},
+		}
+	}
+}
+
+func (app *application) broadcastUpdate(path string, body any, meta metadata) {
+	app.state.mu.RLock()
+	subs := make([]*subscriber, 0, len(app.state.subscribers))
+	for _, sub := range app.state.subscribers {
+		subs = append(subs, sub)
+	}
+	app.state.mu.RUnlock()
+	for _, sub := range subs {
+		select {
+		case <-sub.done:
+			continue
+		default:
+		}
+		if sub.target == targetDocument && sub.path == path {
+			sendNonBlocking(sub.ch, sseEvent{Event: "update", Data: documentResponse{Path: path, Doc: body, Meta: meta}})
+			continue
+		}
+		if sub.target == targetCollection && isDirectChild(sub.path, path) {
+			name := lastPathSegment(path)
+			if sub.interval.contains(name) {
+				sendNonBlocking(sub.ch, sseEvent{Event: "update", Data: collectionEntry{Path: path, Doc: body, Meta: meta}})
+			}
+		}
+	}
+}
+
+func (app *application) broadcastDelete(path string, name string, isCollection bool) {
+	app.state.mu.RLock()
+	subs := make([]*subscriber, 0, len(app.state.subscribers))
+	for _, sub := range app.state.subscribers {
+		subs = append(subs, sub)
+	}
+	app.state.mu.RUnlock()
+	for _, sub := range subs {
+		select {
+		case <-sub.done:
+			continue
+		default:
+		}
+		if sub.target == targetDocument && sub.path == path {
+			sendNonBlocking(sub.ch, sseEvent{Event: "delete", Data: map[string]any{"path": path}})
+			continue
+		}
+		if sub.target == targetCollection {
+			if path == sub.path && isCollection {
+				sendNonBlocking(sub.ch, sseEvent{Event: "delete", Data: map[string]any{"path": path}})
+				continue
+			}
+			if isDirectChild(sub.path, path) && sub.interval.contains(name) {
+				sendNonBlocking(sub.ch, sseEvent{Event: "delete", Data: map[string]any{"path": path}})
+			}
+		}
+	}
+}
+
+func sendNonBlocking(ch chan sseEvent, evt sseEvent) {
+	select {
+	case ch <- evt:
+	default:
+	}
+}
+
+func writeSSE(w http.ResponseWriter, id int64, evt sseEvent) error {
+	payload, err := json.Marshal(evt.Data)
+	if err != nil {
+		return err
+	}
+	_, err = fmt.Fprintf(w, "id: %d\nevent: %s\ndata: %s\n\n", id, evt.Event, payload)
+	return err
+}
+
+func readJSONDocument(r *http.Request) ([]byte, jsondata.JSONValue, any, error) {
+	raw, err := readBodyBytes(r)
+	if err != nil {
+		return nil, jsondata.JSONValue{}, nil, err
+	}
+	var value jsondata.JSONValue
+	if err := json.Unmarshal(raw, &value); err != nil {
+		return nil, jsondata.JSONValue{}, nil, errors.New("invalid json")
+	}
+	docAny, err := jsonValueToAny(value)
+	if err != nil {
+		return nil, jsondata.JSONValue{}, nil, errors.New("invalid json")
+	}
+	return raw, value, docAny, nil
+}
+
+func readBodyBytes(r *http.Request) ([]byte, error) {
+	defer r.Body.Close()
+	var body any
+	if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
+		return nil, err
+	}
+	return json.Marshal(body)
+}
+
+func (app *application) lookupDocumentContainerLocked(parts []string) (*document, map[string]*document, string, error) {
+	if len(parts) < 2 || len(parts)%2 != 0 {
+		return nil, nil, "", errors.New("invalid document path")
+	}
+	name := parts[len(parts)-1]
+	parentDocs, err := app.getCollectionDocsLocked(parts[:len(parts)-1])
+	if err != nil {
+		return nil, nil, "", err
+	}
+	return parentDocs[name], parentDocs, name, nil
+}
+
+func (app *application) getCollectionDocsLocked(parts []string) (map[string]*document, error) {
+	if len(parts) == 0 {
+		return nil, errors.New("root collection unsupported")
+	}
+	db, ok := app.state.dbs[parts[0]]
+	if !ok {
+		return nil, errors.New("database not found")
+	}
+	if len(parts) == 1 {
+		return db.Docs, nil
+	}
+	doc, err := app.getDocumentLocked(parts[:len(parts)-1])
+	if err != nil {
+		return nil, err
+	}
+	col := doc.Collections[parts[len(parts)-1]]
+	if col == nil {
+		return nil, errors.New("collection not found")
+	}
+	return col.Docs, nil
+}
+
+func (app *application) getDocumentLocked(parts []string) (*document, error) {
+	if len(parts) < 2 || len(parts)%2 != 0 {
+		return nil, errors.New("document not found")
+	}
+	db, ok := app.state.dbs[parts[0]]
+	if !ok {
+		return nil, errors.New("database not found")
+	}
+	doc := db.Docs[parts[1]]
+	if doc == nil {
+		return nil, errors.New("document not found")
+	}
+	for i := 2; i < len(parts); i += 2 {
+		col := doc.Collections[parts[i]]
+		if col == nil {
+			return nil, errors.New("collection not found")
+		}
+		doc = col.Docs[parts[i+1]]
+		if doc == nil {
+			return nil, errors.New("document not found")
+		}
+	}
+	return doc, nil
+}
+
+func parseInterval(s string) (interval, error) {
+	if s == "" {
+		return interval{}, nil
+	}
+	if !strings.HasPrefix(s, "[") || !strings.HasSuffix(s, "]") {
+		return interval{}, errors.New("invalid interval")
+	}
+	body := strings.TrimSuffix(strings.TrimPrefix(s, "["), "]")
+	parts := strings.SplitN(body, ",", 2)
+	if len(parts) != 2 {
+		return interval{}, errors.New("invalid interval")
+	}
+	return interval{Low: parts[0], High: parts[1]}, nil
+}
+
+func (iv interval) contains(name string) bool {
+	if iv.Low != "" && name < iv.Low {
+		return false
+	}
+	if iv.High != "" && name > iv.High {
+		return false
+	}
+	return true
+}
+
+func applyPatch(root *any, op patchOp) error {
+	switch op.Op {
+	case "ArrayAdd":
+		target, err := resolvePointer(*root, op.Path)
+		if err != nil {
+			return err
+		}
+		arr, ok := target.([]any)
+		if !ok {
+			return errors.New("path does not reference array")
+		}
+		val, err := jsonValueToAny(op.Value)
+		if err != nil {
+			return err
+		}
+		for _, item := range arr {
+			if deepEqualJSON(item, val) {
+				return nil
+			}
+		}
+		replacePointer(root, op.Path, append(arr, val))
+		return nil
+	case "ArrayRemove":
+		target, err := resolvePointer(*root, op.Path)
+		if err != nil {
+			return err
+		}
+		arr, ok := target.([]any)
+		if !ok {
+			return errors.New("path does not reference array")
+		}
+		val, err := jsonValueToAny(op.Value)
+		if err != nil {
+			return err
+		}
+		next := make([]any, 0, len(arr))
+		for _, item := range arr {
+			if !deepEqualJSON(item, val) {
+				next = append(next, item)
+			}
+		}
+		replacePointer(root, op.Path, next)
+		return nil
+	case "ObjectAdd":
+		parentPath, key, err := splitPointerParent(op.Path)
+		if err != nil {
+			return err
+		}
+		target, err := resolvePointer(*root, parentPath)
+		if err != nil {
+			return err
+		}
+		obj, ok := target.(map[string]any)
+		if !ok {
+			return errors.New("path does not reference object")
+		}
+		if _, exists := obj[key]; exists {
+			return nil
+		}
+		val, err := jsonValueToAny(op.Value)
+		if err != nil {
+			return err
+		}
+		obj[key] = val
+		return nil
+	default:
+		return errors.New("invalid patch operation")
+	}
+}
+
+func splitPointerParent(path string) (string, string, error) {
+	if path == "" || path == "/" || !strings.HasPrefix(path, "/") {
+		return "", "", errors.New("invalid patch path")
+	}
+	parts := decodePointer(path)
+	if len(parts) == 0 {
+		return "", "", errors.New("invalid patch path")
+	}
+	if len(parts) == 1 {
+		return "", parts[0], nil
+	}
+	return "/" + strings.Join(parts[:len(parts)-1], "/"), parts[len(parts)-1], nil
+}
+
+func resolvePointer(root any, path string) (any, error) {
+	if path == "" {
+		return root, nil
+	}
+	if !strings.HasPrefix(path, "/") {
+		return nil, errors.New("invalid patch path")
+	}
+	cur := root
+	for _, part := range decodePointer(path) {
+		obj, ok := cur.(map[string]any)
+		if !ok {
+			return nil, errors.New("patch path not found")
+		}
+		next, exists := obj[part]
+		if !exists {
+			return nil, errors.New("patch path not found")
+		}
+		cur = next
+	}
+	return cur, nil
+}
+
+func replacePointer(root *any, path string, val any) {
+	if path == "" {
+		*root = val
+		return
+	}
+	parts := decodePointer(path)
+	cur := *root
+	for i := 0; i < len(parts)-1; i++ {
+		cur = cur.(map[string]any)[parts[i]]
+	}
+	cur.(map[string]any)[parts[len(parts)-1]] = val
+}
+
+func decodePointer(path string) []string {
+	if path == "" {
+		return nil
+	}
+	parts := strings.Split(strings.TrimPrefix(path, "/"), "/")
+	for i, part := range parts {
+		part = strings.ReplaceAll(part, "~1", "/")
+		part = strings.ReplaceAll(part, "~0", "~")
+		parts[i] = part
+	}
+	return parts
+}
+
+type anyVisitor struct{}
+
+func (anyVisitor) Map(m map[string]jsondata.JSONValue) (any, error) {
+	out := make(map[string]any, len(m))
+	for k, v := range m {
+		converted, err := jsonValueToAny(v)
+		if err != nil {
+			return nil, err
+		}
+		out[k] = converted
+	}
+	return out, nil
+}
+
+func (anyVisitor) Slice(s []jsondata.JSONValue) (any, error) {
+	out := make([]any, len(s))
+	for i, v := range s {
+		converted, err := jsonValueToAny(v)
+		if err != nil {
+			return nil, err
+		}
+		out[i] = converted
+	}
+	return out, nil
+}
+
+func (anyVisitor) Bool(v bool) (any, error)     { return v, nil }
+func (anyVisitor) Float64(v float64) (any, error) { return v, nil }
+func (anyVisitor) String(v string) (any, error) { return v, nil }
+func (anyVisitor) Null() (any, error)           { return nil, nil }
+
+func jsonValueToAny(v jsondata.JSONValue) (any, error) {
+	return jsondata.Accept[any](v, anyVisitor{})
+}
+
+func mustJSONValueToAny(v jsondata.JSONValue) any {
+	out, _ := jsonValueToAny(v)
+	return out
+}
+
+func deepCopyAny(v any) any {
+	data, _ := json.Marshal(v)
+	var copied any
+	_ = json.Unmarshal(data, &copied)
+	return copied
+}
+
+func deepEqualJSON(a, b any) bool {
+	ab, _ := json.Marshal(a)
+	bb, _ := json.Marshal(b)
+	return string(ab) == string(bb)
+}
+
+func isDirectChild(collectionPath string, itemPath string) bool {
+	if !strings.HasPrefix(collectionPath, "/v1/") || !strings.HasPrefix(itemPath, "/v1/") {
+		return false
+	}
+	base := strings.TrimSuffix(strings.TrimPrefix(collectionPath, "/v1/"), "/")
+	item := strings.TrimPrefix(itemPath, "/v1/")
+	if !strings.HasPrefix(item, base+"/") {
+		return false
+	}
+	rest := strings.TrimPrefix(item, base+"/")
+	return !strings.Contains(rest, "/")
+}
+
+func lastPathSegment(path string) string {
+	trimmed := strings.TrimSuffix(path, "/")
+	if trimmed == "" {
+		return ""
+	}
+	parts := strings.Split(trimmed, "/")
+	return parts[len(parts)-1]
+}
+
+func generateToken(username string) string {
+	buf := make([]byte, 8)
+	if _, err := rand.Read(buf); err != nil {
+		return fmt.Sprintf("token_%s_%d", username, time.Now().UnixNano())
+	}
+	return "token_" + username + "_" + hex.EncodeToString(buf)
+}
+
+func writeJSON(w http.ResponseWriter, status int, body any) {
+	w.Header().Set("Content-Type", "application/json")
+	w.WriteHeader(status)
+	_ = json.NewEncoder(w).Encode(body)
+}
+
+func writeError(w http.ResponseWriter, status int, message string) {
+	writeJSON(w, status, map[string]string{"error": message})
+}
+
+func shutdownContext() (context.Context, context.CancelFunc) {
+	return context.WithTimeout(context.Background(), 5*time.Second)
+}
